SELECT FROM kb_chunk WHERE chunk_type = 'child' AND status = 'active' AND content_vector IS NOT NULL
AND kb_id = #{kbId}
ORDER BY content_vector <=> #{vectorStr}::vector LIMIT #{topK}

SELECT , ts_rank(tsv, websearch_to_tsquery('zh_cn', #{query})) AS rank FROM kb_chunk WHERE chunk_type = 'child' AND status = 'active' AND tsv @@ websearch_to_tsquery('zh_cn', #{query})
AND kb_id = #{kbId}
ORDER BY rank DESC LIMIT #{topK}
